import Layout from "../../components/layout/Layout";

const resources = [
  { name: "Dell Laptop", type: "Hardware", available: 3 },
  { name: "Operating System Book", type: "Book", available: 7 },
  { name: "MATLAB License", type: "Software", available: 10 },
];

const BrowseResources = () => {
  return (
    <Layout>

      <h1 style={{marginBottom:"20px"}}>Resources</h1>

      <div className="resource-grid">

        {resources.map((r, i) => (

          <div className="resource-card" key={i}>

            <h3>{r.name}</h3>

            <p>Type: {r.type}</p>

            <p>Available: {r.available}</p>

            <button className="button">
              Request Resource
            </button>

          </div>

        ))}

      </div>

    </Layout>
  );
};

export default BrowseResources;
